const checkpoints = [];

const currentCartId = localStorage.getItem('currentCartId');
const cartItemsAll = JSON.parse(localStorage.getItem('cart_items') || '[]');
const activities = JSON.parse(localStorage.getItem('tour_activities') || '[]');
const sessions = JSON.parse(localStorage.getItem('activity_sessions') || '[]');
const addons = JSON.parse(localStorage.getItem('addons') || '[]');

const tourCartItems = cartItemsAll.filter(function(ci) {
  return ci.cartId === currentCartId && ci.item_type === 'tour_activity_session';
});

// Find tour items that match: family-friendly tour, weekend morning in 09:00-11:00 window, 2 adults + 2 children, base tour total <= 100
const qualifyingTourItems = tourCartItems.filter(function(ci) {
  const session = sessions.find(function(s) { return s.id === ci.activitySessionId; });
  if (!session || session.status !== 'available') return false;
  const activity = activities.find(function(a) { return a.id === session.activityId; });
  if (!activity) return false;

  // Must be a tour and family-friendly
  if (activity.activity_type !== 'tour') return false;
  if (activity.audience !== 'family_friendly') return false;

  // Weekend + morning and within 09:00-11:00
  if (!session.is_weekend) return false;
  if (session.time_of_day !== 'morning') return false;
  const start = session.start_datetime || '';
  const timePart = start.slice(11, 16); // 'HH:MM'
  if (!timePart || timePart < '09:00' || timePart > '11:00') return false;

  // Participant counts
  const adults = ci.participants_adults || 0;
  const children = ci.participants_children || 0;
  if (adults !== 2 || children !== 2) return false;

  // Base tour total (excluding addons) must be <= 100
  const priceAdult = typeof session.price_adult === 'number' ? session.price_adult : (activity.base_price_adult || 0);
  const priceChild = typeof session.price_child === 'number' ? session.price_child : (activity.base_price_child || 0);
  const baseTotal = priceAdult * adults + priceChild * children;
  if (baseTotal > 100) return false;

  return true;
});

// CP1 (0.6): User has at least one qualifying weekend morning family tour for 2 adults + 2 children with base total <= 100
checkpoints.push({ passed: qualifyingTourItems.length > 0, weight: 0.6 });

// Among those, check for a picnic-style food addon around $15
const qualifyingWithPicnic = qualifyingTourItems.filter(function(ci) {
  const selectedIds = Array.isArray(ci.selected_addon_ids) ? ci.selected_addon_ids : [];
  return selectedIds.some(function(aid) {
    const addon = addons.find(function(a) { return a.id === aid; });
    if (!addon) return false;
    if (addon.category !== 'food') return false;
    const text = ((addon.name || '') + ' ' + (addon.description || '')).toLowerCase();
    if (text.indexOf('picnic') === -1) return false;
    if (typeof addon.price !== 'number') return false;
    // "Around $15" – allow a reasonable band, e.g. $10-$20
    if (addon.price < 10 || addon.price > 20) return false;
    return true;
  });
});

// CP2 (0.4): At least one qualifying tour item also has a suitable picnic-style food addon
checkpoints.push({ passed: qualifyingWithPicnic.length > 0, weight: 0.4 });

return checkpoints.reduce(function(sum, cp) { return sum + (cp.passed ? cp.weight : 0); }, 0);

const checkpoints = [];

// --- Check search/filter usage ---
const filterParams = JSON.parse(localStorage.getItem('task2_socksFilterParams') || 'null');

const usedCorrectFilter = !!(filterParams &&
  filterParams.category_slug === 'socks' &&
  filterParams.filters &&
  Array.isArray(filterParams.filters.sizes) &&
  filterParams.filters.sizes.some(function(s) { return String(s).toLowerCase() === 'medium'; })
);

// CP1 (0.3): User searched in socks category with a medium size filter
checkpoints.push({ passed: usedCorrectFilter, weight: 0.3 });

// --- Check cart contents for qualifying socks ---
const currentCartId = localStorage.getItem('currentCartId');
const cartItemsAll = JSON.parse(localStorage.getItem('cart_items') || '[]');
const products = JSON.parse(localStorage.getItem('products') || '[]');
const variants = JSON.parse(localStorage.getItem('product_variants') || '[]');
const categories = JSON.parse(localStorage.getItem('product_categories') || '[]');

const socksCategory = categories.find(function(c) { return c.slug === 'socks'; });
const socksCategoryId = socksCategory ? socksCategory.id : null;

const productCartItems = cartItemsAll.filter(function(ci) {
  return ci.cartId === currentCartId && ci.item_type === 'product';
});

const qualifyingItems = productCartItems.filter(function(ci) {
  const product = products.find(function(p) { return p.id === ci.productId; });
  if (!product) return false;
  if (product.categoryId !== socksCategoryId) return false;

  // Price under $25, considering variant override if present
  let price = product.price || 0;
  if (ci.variantId) {
    const variant = variants.find(function(v) { return v.id === ci.variantId; });
    if (variant && typeof variant.price_override === 'number') {
      price = variant.price_override;
    }
  }
  if (!(price < 25)) return false;

  // Must be medium size: via variant.size or product tags like 'size_medium'
  let hasMedium = false;
  if (ci.variantId) {
    const variant = variants.find(function(v) { return v.id === ci.variantId; });
    if (variant && String(variant.size || '').toLowerCase() === 'medium') {
      hasMedium = true;
    }
  }
  if (!hasMedium) {
    const tags = Array.isArray(product.tags) ? product.tags : [];
    hasMedium = tags.some(function(t) {
      return typeof t === 'string' && t.toLowerCase() === 'size_medium';
    });
  }
  if (!hasMedium) return false;

  // Must be llama wool socks: use tag 'llama_wool'
  const tags = Array.isArray(product.tags) ? product.tags : [];
  const isLlamaWool = tags.some(function(t) {
    return typeof t === 'string' && t.toLowerCase().indexOf('llama_wool') !== -1;
  });
  if (!isLlamaWool) return false;

  return true;
});

// Distinct qualifying products
const distinctProductIds = Array.from(new Set(qualifyingItems.map(function(ci) { return ci.productId; })));

// CP2 (0.7): At least 3 different qualifying medium llama wool sock products under $25 are in the current cart
checkpoints.push({ passed: distinctProductIds.length >= 3, weight: 0.7 });

return checkpoints.reduce(function(sum, cp) { return sum + (cp.passed ? cp.weight : 0); }, 0);

const checkpoints = [];

const packages = JSON.parse(localStorage.getItem('party_packages') || '[]');
const inquiries = JSON.parse(localStorage.getItem('group_package_inquiries') || '[]');

// Find birthday-party inquiries matching June Saturday, ~10 kids, indoor/all-weather, cupcake upgrade
const juneSaturdayBirthdayInquiries = inquiries.filter(function(inq) {
  const pkg = packages.find(function(p) { return p.id === inq.packageId; });
  if (!pkg || pkg.type !== 'birthday') return false;
  if (!inq.requested_date) return false;
  const d = new Date(inq.requested_date);
  if (isNaN(d.getTime())) return false;
  // June (month index 5) and Saturday (6)
  if (d.getUTCMonth() !== 5) return false;
  if (d.getUTCDay() !== 6) return false;

  const kids = inq.num_children;
  if (typeof kids !== 'number' || kids < 8 || kids > 12) return false;

  if (inq.location_type !== 'indoor_friendly' && inq.location_type !== 'indoor') return false;
  if (!inq.include_cupcake_upgrade) return false;

  if (!inq.contact_name || !inq.contact_email || !inq.contact_phone) return false;

  return true;
});

// CP1 (0.6): At least one qualifying June Saturday birthday party inquiry with ~10 kids, indoor(-friendly), cupcake upgrade, and contact details
checkpoints.push({ passed: juneSaturdayBirthdayInquiries.length > 0, weight: 0.6 });

// From those, check for an approximately 2-hour visit duration (or package duration ~120 minutes)
const twoHourInquiries = juneSaturdayBirthdayInquiries.filter(function(inq) {
  const pkg = packages.find(function(p) { return p.id === inq.packageId; });

  // Prefer explicit visit start/end if available
  if (inq.visit_start_datetime && inq.visit_end_datetime) {
    const start = new Date(inq.visit_start_datetime);
    const end = new Date(inq.visit_end_datetime);
    if (!isNaN(start.getTime()) && !isNaN(end.getTime())) {
      const minutes = (end.getTime() - start.getTime()) / (1000 * 60);
      if (minutes < 110 || minutes > 130) return false;
    }
  }

  if (pkg && typeof pkg.duration_minutes === 'number') {
    if (pkg.duration_minutes < 110 || pkg.duration_minutes > 130) return false;
  }

  return true;
});

// CP2 (0.4): At least one of those inquiries reflects an approximately 2-hour party duration
checkpoints.push({ passed: twoHourInquiries.length > 0, weight: 0.4 });

return checkpoints.reduce(function(sum, cp) { return sum + (cp.passed ? cp.weight : 0); }, 0);

const checkpoints = [];

const itineraries = JSON.parse(localStorage.getItem('itineraries') || '[]');
const itineraryItems = JSON.parse(localStorage.getItem('itinerary_items') || '[]');
const activitySessions = JSON.parse(localStorage.getItem('activity_sessions') || '[]');
const tourActivities = JSON.parse(localStorage.getItem('tour_activities') || '[]');
const workshopSessions = JSON.parse(localStorage.getItem('workshop_sessions') || '[]');
const workshops = JSON.parse(localStorage.getItem('workshops') || '[]');

let candidateItineraries = [];
const currentItId = localStorage.getItem('currentItineraryId');
if (currentItId) {
  const it = itineraries.find(function(x) { return x.id === currentItId; });
  if (it) candidateItineraries.push(it);
}
if (!candidateItineraries.length) {
  candidateItineraries = itineraries.slice();
}

let found = null; // { itinerary, day1TourItem, day1WalkItem, day2WorkshopItem }

for (let i = 0; i < candidateItineraries.length && !found; i++) {
  const it = candidateItineraries[i];
  if (!it.start_date || !it.end_date) continue;
  const startDate = new Date(it.start_date);
  const endDate = new Date(it.end_date);
  if (isNaN(startDate.getTime()) || isNaN(endDate.getTime())) continue;
  const diffDays = Math.round((endDate.getTime() - startDate.getTime()) / (1000 * 60 * 60 * 24));
  // Treat 1-2 day span as a 2-day visit window
  if (diffDays < 1 || diffDays > 2) continue;

  const allItems = itineraryItems.filter(function(ii) { return ii.itineraryId === it.id; });
  if (allItems.length < 3) continue;

  const day1Str = it.start_date.slice(0, 10);
  const day2Str = new Date(startDate.getTime() + 24 * 60 * 60 * 1000).toISOString().slice(0, 10);

  let day1TourItem = null;
  let day1WalkItem = null;
  let day2WorkshopItem = null;

  for (let j = 0; j < allItems.length; j++) {
    const ii = allItems[j];
    const dateStr = ii.date ? ii.date.slice(0, 10) : null;

    if (dateStr === day1Str && ii.item_type === 'tour_activity_session') {
      const sess = activitySessions.find(function(s) { return s.id === ii.activitySessionId; });
      if (!sess) continue;
      const act = tourActivities.find(function(a) { return a.id === sess.activityId; });
      if (!act) continue;
      if (ii.participants !== 2) continue;

      if (!day1TourItem && act.activity_type === 'tour') {
        day1TourItem = ii;
      }
      if (!day1WalkItem && act.activity_type === 'walk') {
        day1WalkItem = ii;
      }
    }

    if (dateStr === day2Str && ii.item_type === 'workshop_session') {
      const wsess = workshopSessions.find(function(s) { return s.id === ii.workshopSessionId; });
      if (!wsess) continue;
      const w = workshops.find(function(wk) { return wk.id === wsess.workshopId; });
      if (!w) continue;
      if (w.topic !== 'fiber') continue;
      if (ii.participants !== 2) continue;
      if (!day2WorkshopItem) {
        day2WorkshopItem = ii;
      }
    }
  }

  if (day1TourItem && day1WalkItem && day2WorkshopItem) {
    found = { itinerary: it, day1TourItem: day1TourItem, day1WalkItem: day1WalkItem, day2WorkshopItem: day2WorkshopItem };
  }
}

// CP1 (0.6): An itinerary exists spanning about 2 days with day 1 tour+walk and day 2 fiber workshop, each for 2 participants
checkpoints.push({ passed: !!found, weight: 0.6 });

let allBefore1pm = false;
if (found) {
  const day1TourSession = activitySessions.find(function(s) { return s.id === found.day1TourItem.activitySessionId; });
  const day1WalkSession = activitySessions.find(function(s) { return s.id === found.day1WalkItem.activitySessionId; });
  const day2WorkshopSession = workshopSessions.find(function(s) { return s.id === found.day2WorkshopItem.workshopSessionId; });

  const times = [];
  if (day1TourSession && day1TourSession.start_datetime) times.push(day1TourSession.start_datetime.slice(11, 16));
  if (day1WalkSession && day1WalkSession.start_datetime) times.push(day1WalkSession.start_datetime.slice(11, 16));
  if (day2WorkshopSession && day2WorkshopSession.start_datetime) times.push(day2WorkshopSession.start_datetime.slice(11, 16));

  allBefore1pm = times.length === 3 && times.every(function(t) { return t < '13:00'; });
}

// CP2 (0.4): All three activities in the qualifying itinerary start before 13:00
checkpoints.push({ passed: allBefore1pm, weight: 0.4 });

return checkpoints.reduce(function(sum, cp) { return sum + (cp.passed ? cp.weight : 0); }, 0);

const checkpoints = [];

const products = JSON.parse(localStorage.getItem('gift_card_products') || '[]');
const designs = JSON.parse(localStorage.getItem('gift_card_designs') || '[]');
const purchases = JSON.parse(localStorage.getItem('gift_card_purchases') || '[]');
const carts = JSON.parse(localStorage.getItem('carts') || '[]');
const cartItemsAll = JSON.parse(localStorage.getItem('cart_items') || '[]');
const meta = JSON.parse(localStorage.getItem('_metadata') || 'null');

let baselineDate = null;
if (meta && meta.baselineDate) {
  baselineDate = new Date(meta.baselineDate + 'T00:00:00Z');
}

let qualifyingPurchase = null;

for (let i = 0; i < purchases.length && !qualifyingPurchase; i++) {
  const p = purchases[i];
  const product = products.find(function(gp) { return gp.id === p.giftCardProductId; });
  const design = designs.find(function(d) { return d.id === p.designId; });
  if (!product || !design) continue;

  if (product.type !== 'digital') continue;
  if (typeof p.amount !== 'number' || p.amount < 50 || p.amount > 100) continue;
  if (!design.is_llama_themed) continue;
  if (!p.recipient_email) continue;
  if (!p.message) continue;
  if (!p.delivery_date) continue;

  const deliv = new Date(p.delivery_date);
  if (isNaN(deliv.getTime())) continue;

  let meetsOffset = true;
  if (baselineDate) {
    const diffDays = (deliv.getTime() - baselineDate.getTime()) / (1000 * 60 * 60 * 24);
    if (diffDays < 7 - 1e-6) {
      meetsOffset = false;
    }
  }
  if (!meetsOffset) continue;

  qualifyingPurchase = p;
}

// CP1 (0.6): A qualifying digital llama-themed gift card (amount $50–$100, email, >=7 days after baseline) exists
checkpoints.push({ passed: !!qualifyingPurchase, weight: 0.6 });

let inCart = false;
if (qualifyingPurchase) {
  const currentCartId = localStorage.getItem('currentCartId');
  const cartItems = cartItemsAll.filter(function(ci) {
    return ci.cartId === currentCartId && ci.item_type === 'gift_card';
  });
  inCart = cartItems.some(function(ci) {
    return ci.giftCardPurchaseId === qualifyingPurchase.id && (ci.quantity || 0) >= 1;
  });
}

// CP2 (0.4): The qualifying gift card purchase is present as a gift_card item in the current cart
checkpoints.push({ passed: inCart, weight: 0.4 });

return checkpoints.reduce(function(sum, cp) { return sum + (cp.passed ? cp.weight : 0); }, 0);

const checkpoints = [];

const workshops = JSON.parse(localStorage.getItem('workshops') || '[]');
const sessions = JSON.parse(localStorage.getItem('workshop_sessions') || '[]');
const promos = JSON.parse(localStorage.getItem('promo_codes') || '[]');
const cartItemsAll = JSON.parse(localStorage.getItem('cart_items') || '[]');

const currentCartId = localStorage.getItem('currentCartId');
const cartItems = cartItemsAll.filter(function(ci) {
  return ci.cartId === currentCartId && ci.item_type === 'workshop_session';
});

let qualifyingItem = null;

for (let i = 0; i < cartItems.length && !qualifyingItem; i++) {
  const ci = cartItems[i];
  const session = sessions.find(function(s) { return s.id === ci.workshopSessionId; });
  if (!session) continue;
  const workshop = workshops.find(function(w) { return w.id === session.workshopId; });
  if (!workshop) continue;

  if (workshop.topic !== 'fiber') continue;
  if (workshop.skill_level !== 'beginner') continue;
  if (session.price > 50) continue;

  const adults = (ci.guests_adults || ci.participants_adults || 0);
  const children = (ci.guests_children || ci.participants_children || 0);
  const attendees = adults + children;
  if (attendees !== 1) continue;

  if (!ci.promo_code || String(ci.promo_code).toUpperCase() !== 'LLAMA10') continue;
  if (typeof ci.discount_amount !== 'number') continue;

  const expectedDiscount = (session.price || 0) * attendees * 0.10;
  if (Math.abs(ci.discount_amount - expectedDiscount) > 0.05) continue;

  qualifyingItem = ci;
}

// CP1 (0.6): A cart item exists for a beginner fiber workshop under $50 for exactly one attendee with LLAMA10 applied at ~10% discount
checkpoints.push({ passed: !!qualifyingItem, weight: 0.6 });

let isEarliest = false;
if (qualifyingItem) {
  const session = sessions.find(function(s) { return s.id === qualifyingItem.workshopSessionId; });
  if (session) {
    const workshopId = session.workshopId;
    const available = sessions.filter(function(s) {
      if (s.workshopId !== workshopId) return false;
      if (s.status && s.status !== 'available') return false;
      if (typeof s.capacity_remaining === 'number' && s.capacity_remaining <= 0) return false;
      return true;
    });
    available.sort(function(a, b) {
      const da = new Date(a.start_datetime || a.date || 0).getTime();
      const db = new Date(b.start_datetime || b.date || 0).getTime();
      return da - db;
    });
    const earliest = available[0];
    isEarliest = !!(earliest && earliest.id === session.id);
  }
}

// CP2 (0.4): The chosen workshop session is the earliest available session for that workshop
checkpoints.push({ passed: isEarliest, weight: 0.4 });

return checkpoints.reduce(function(sum, cp) { return sum + (cp.passed ? cp.weight : 0); }, 0);

const checkpoints = [];

const lodgings = JSON.parse(localStorage.getItem('lodging_properties') || '[]');
const ratePlans = JSON.parse(localStorage.getItem('rate_plans') || '[]');
const calendars = JSON.parse(localStorage.getItem('rate_plan_calendar') || '[]');
const cartItemsAll = JSON.parse(localStorage.getItem('cart_items') || '[]');

const currentCartId = localStorage.getItem('currentCartId');
const stayItems = cartItemsAll.filter(function(ci) {
  return ci.cartId === currentCartId && ci.item_type === 'lodging_stay';
});

let qualifyingStay = null;

for (let i = 0; i < stayItems.length && !qualifyingStay; i++) {
  const ci = stayItems[i];
  const lodging = lodgings.find(function(l) { return l.id === ci.lodgingId; });
  const ratePlan = ratePlans.find(function(rp) { return rp.id === ci.ratePlanId; });
  if (!lodging || !ratePlan) continue;

  const amenities = Array.isArray(lodging.amenities) ? lodging.amenities : [];
  if (amenities.indexOf('pasture_view') === -1) continue;
  if (!ratePlan.includes_breakfast) continue;

  const adults = ci.guests_adults || ci.participants_adults || 0;
  const children = ci.guests_children || ci.participants_children || 0;
  if (adults !== 2 || children !== 0) continue;

  if (!ci.check_in_date || !ci.check_out_date) continue;
  const checkIn = new Date(ci.check_in_date);
  const checkOut = new Date(ci.check_out_date);
  if (isNaN(checkIn.getTime()) || isNaN(checkOut.getTime())) continue;

  const nights = Math.round((checkOut.getTime() - checkIn.getTime()) / (1000 * 60 * 60 * 24));
  if (nights !== 2) continue;

  // Same month constraint: compare check-in month to (check-out minus one day) month
  const endMinusOne = new Date(checkOut.getTime() - 24 * 60 * 60 * 1000);
  if (checkIn.getUTCMonth() !== endMinusOne.getUTCMonth()) continue;

  if (typeof ci.total_price !== 'number' || ci.total_price > 300) continue;

  qualifyingStay = ci;
}

// CP1 (0.6): A qualifying 2-night pasture-view cabin stay with breakfast for 2 adults, same month, total <= $300 exists in the current cart
checkpoints.push({ passed: !!qualifyingStay, weight: 0.6 });

let pricingConsistent = false;
if (qualifyingStay) {
  const ratePlan = ratePlans.find(function(rp) { return rp.id === qualifyingStay.ratePlanId; });
  const checkIn = new Date(qualifyingStay.check_in_date);
  const checkOut = new Date(qualifyingStay.check_out_date);
  const nights = Math.round((checkOut.getTime() - checkIn.getTime()) / (1000 * 60 * 60 * 24));

  let sumRates = 0;
  let allAvailable = true;
  for (let n = 0; n < nights; n++) {
    const date = new Date(checkIn.getTime() + n * 24 * 60 * 60 * 1000);
    const dateStr = date.toISOString().slice(0, 10);
    const cal = calendars.find(function(c) {
      const d = c.date ? c.date.slice(0, 10) : null;
      return c.ratePlanId === ratePlan.id && d === dateStr;
    });
    if (!cal || cal.is_available === false) {
      allAvailable = false;
      break;
    }
    sumRates += cal.nightly_rate || 0;
  }

  const total = qualifyingStay.total_price || qualifyingStay.unit_price || 0;
  pricingConsistent = allAvailable && Math.abs(sumRates - total) < 0.01;
}

// CP2 (0.4): The stay's total matches the sum of available nightly rates for the selected breakfast-inclusive rate plan
checkpoints.push({ passed: pricingConsistent, weight: 0.4 });

return checkpoints.reduce(function(sum, cp) { return sum + (cp.passed ? cp.weight : 0); }, 0);

const checkpoints = [];

const packages = JSON.parse(localStorage.getItem('party_packages') || '[]');
const inquiries = JSON.parse(localStorage.getItem('group_package_inquiries') || '[]');

const fieldTripPackages = packages.filter(function(p) { return p.type === 'school_field_trip'; });

const qualifyingInquiries = inquiries.filter(function(inq) {
  const pkg = fieldTripPackages.find(function(p) { return p.id === inq.packageId; });
  if (!pkg) return false;

  if (typeof inq.num_students !== 'number' || inq.num_students !== 25) return false;
  if (typeof inq.num_chaperones !== 'number' || inq.num_chaperones !== 3) return false;

  if (!inq.requested_date) return false;
  const d = new Date(inq.requested_date);
  if (isNaN(d.getTime())) return false;
  // October (month index 9)
  if (d.getUTCMonth() !== 9) return false;
  // Weekday: Mon-Fri (1-5)
  const dow = d.getUTCDay();
  if (dow === 0 || dow === 6) return false;

  if (inq.educational_focus !== 'animal_care') return false;
  if (!inq.bus_parking_needed) return false;

  if (!inq.school_name || !inq.contact_name || !inq.contact_email || !inq.contact_phone) return false;

  return true;
});

// CP1 (0.6): A qualifying October weekday school field trip inquiry for 25 students, 3 chaperones, animal-care focus, with bus parking and contact info exists
checkpoints.push({ passed: qualifyingInquiries.length > 0, weight: 0.6 });

const twoHourMorningInquiries = qualifyingInquiries.filter(function(inq) {
  if (!inq.visit_start_datetime || !inq.visit_end_datetime) return false;
  const start = new Date(inq.visit_start_datetime);
  const end = new Date(inq.visit_end_datetime);
  if (isNaN(start.getTime()) || isNaN(end.getTime())) return false;

  const minutes = (end.getTime() - start.getTime()) / (1000 * 60);
  if (minutes < 110 || minutes > 130) return false;

  const startTime = inq.visit_start_datetime.slice(11, 16);
  if (startTime > '12:00') return false; // morning window

  return true;
});

// CP2 (0.4): At least one qualifying inquiry specifies an approximately 2-hour morning visit window
checkpoints.push({ passed: twoHourMorningInquiries.length > 0, weight: 0.4 });

return checkpoints.reduce(function(sum, cp) { return sum + (cp.passed ? cp.weight : 0); }, 0);
